import { A } from "@solidjs/router";
import { graphql } from "relay-runtime";
import { Show } from "solid-js";
import { createFragment } from "solid-relay";
import { Tabs, TabsList, TabsTrigger } from "~/components/ui/tabs.tsx";
import { useLingui } from "~/lib/i18n/macro.d.ts";
import type { ProfileTabs_actor$key } from "./__generated__/ProfileTabs_actor.graphql.ts";

export type ProfileTab = "posts" | "notes" | "articles" | "shares";

export interface ProfileTabsProps {
  selected: ProfileTab;
  $actor: ProfileTabs_actor$key;
}

export function ProfileTabs(props: ProfileTabsProps) {
  const { t } = useLingui();
  const actor = createFragment(
    graphql`
      fragment ProfileTabs_actor on Actor {
        handle
        local
        username
      }
    `,
    () => props.$actor,
  );

  return (
    <Show when={actor()}>
      {(actor) => {
        const baseUrl = () =>
          actor().local ? `/@${actor().username}` : `/${actor().handle}`;
        return (
          <Tabs value={props.selected}>
            <TabsList class="grid grid-cols-4">
              <TabsTrigger as={A} value="posts" href={baseUrl()}>
                {t`Posts`}
              </TabsTrigger>
              <TabsTrigger as={A} value="notes" href={`${baseUrl()}/notes`}>
                {t`Notes`}
              </TabsTrigger>
              <TabsTrigger
                as={A}
                value="articles"
                href={`${baseUrl()}/articles`}
              >
                {t`Articles`}
              </TabsTrigger>
              <TabsTrigger as={A} value="shares" href={`${baseUrl()}/shares`}>
                {t`Shares`}
              </TabsTrigger>
            </TabsList>
          </Tabs>
        );
      }}
    </Show>
  );
}

import { compactUrl } from "@hackerspub/models/url";
import { graphql } from "relay-runtime";
import { For, Show } from "solid-js";
import { createFragment } from "solid-relay";
import {
  Avatar,
  AvatarFallback,
  AvatarImage,
} from "~/components/ui/avatar.tsx";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "~/components/ui/tooltip.tsx";
import { msg, plural, useLingui } from "~/lib/i18n/macro.d.ts";
import type { ProfileCard_actor$key } from "./__generated__/ProfileCard_actor.graphql.ts";
import { FollowButton } from "./FollowButton.tsx";
import { Timestamp } from "./Timestamp.tsx";
import { Trans } from "./Trans.tsx";

export interface ProfileCardProps {
  $actor: ProfileCard_actor$key;
}

export function ProfileCard(props: ProfileCardProps) {
  const { t, i18n } = useLingui();
  const actor = createFragment(
    graphql`
      fragment ProfileCard_actor on Actor {
        id
        name
        username
        handle
        avatarUrl
        avatarInitials
        bio
        local
        url
        iri
        followeesCount: followees {
          totalCount
        }
        followersCount: followers {
          totalCount
        }
        followsViewer
        fields {
          name
          value
        }
        account {
          links {
            name
            handle
            icon
            url
            verified
          }
        }
        ...FollowButton_actor
      }
    `,
    () => props.$actor,
  );

  return (
    <Show when={actor()}>
      {(actor) => (
        <>
          <div class="p-4">
            <div class="flex items-center gap-4">
              <Avatar class="size-16">
                <a
                  href={actor().local
                    ? `/@${actor().username}`
                    : actor().url ?? actor().iri}
                  target={actor().local ? undefined : "_blank"}
                >
                  <AvatarImage src={actor().avatarUrl} class="size-16" />
                  <AvatarFallback class="size-16">
                    {actor().avatarInitials}
                  </AvatarFallback>
                </a>
              </Avatar>
              <div class="flex-1">
                <h1 class="text-xl font-semibold">
                  <a
                    innerHTML={actor().name ?? actor().username}
                    href={actor().local
                      ? `/@${actor().username}`
                      : actor().url ?? actor().iri}
                    target={actor().local ? undefined : "_blank"}
                  />
                </h1>
                <div class="text-muted-foreground">
                  <span class="select-all">
                    {actor().handle}
                  </span>
                </div>
              </div>
              <FollowButton $actor={actor()} />
            </div>
          </div>
          <Show when={(actor().bio?.trim() ?? "") !== ""}>
            <div class="p-4 pt-0">
              <div
                innerHTML={actor().bio ?? ""}
                class="mx-auto prose dark:prose-invert"
              />
            </div>
          </Show>
          <Show
            when={actor().account}
            fallback={
              <Show when={actor().fields.length > 0}>
                <div class="p-4 pt-0">
                  <ul>
                    <For each={actor().fields}>
                      {(field) => (
                        <li class="flex flex-row items-center text-sm mb-1">
                          <img
                            src="/icons/web.svg"
                            class="size-3.5 mr-1 dark:invert opacity-65"
                          />
                          <span class="text-muted-foreground mr-1">
                            {field.name}
                          </span>
                          <span innerHTML={field.value}></span>
                        </li>
                      )}
                    </For>
                  </ul>
                </div>
              </Show>
            }
          >
            {(account) => (
              <Show
                when={account().links.length > 0}
              >
                <div class="p-4 pt-0">
                  <ul>
                    <For each={account().links}>
                      {(link) => (
                        <li class="flex flex-row items-center text-sm mb-1">
                          <img
                            src={`/icons/${link.icon.toLowerCase()}.svg`}
                            class="size-3.5 mr-1 dark:invert opacity-65"
                          />
                          <span class="text-muted-foreground mr-1">
                            {link.name}
                          </span>
                          <a href={link.url}>
                            {link.handle ?? compactUrl(link.url)}
                          </a>
                          <Show when={link.verified}>
                            {(verified) => (
                              <Tooltip>
                                <TooltipTrigger>
                                  <svg
                                    xmlns="http://www.w3.org/2000/svg"
                                    fill="none"
                                    viewBox="0 0 24 24"
                                    stroke-width="1.5"
                                    stroke="currentColor"
                                    class="size-4 ml-1 stroke-success-foreground cursor-help"
                                  >
                                    <path
                                      stroke-linecap="round"
                                      stroke-linejoin="round"
                                      d="M9 12.75 11.25 15 15 9.75M21 12c0 1.268-.63 2.39-1.593 3.068a3.745 3.745 0 0 1-1.043 3.296 3.745 3.745 0 0 1-3.296 1.043A3.745 3.745 0 0 1 12 21c-1.268 0-2.39-.63-3.068-1.593a3.746 3.746 0 0 1-3.296-1.043 3.745 3.745 0 0 1-1.043-3.296A3.745 3.745 0 0 1 3 12c0-1.268.63-2.39 1.593-3.068a3.745 3.745 0 0 1 1.043-3.296 3.746 3.746 0 0 1 3.296-1.043A3.746 3.746 0 0 1 12 3c1.268 0 2.39.63 3.068 1.593a3.746 3.746 0 0 1 3.296 1.043 3.746 3.746 0 0 1 1.043 3.296A3.745 3.745 0 0 1 21 12Z"
                                    />
                                  </svg>
                                </TooltipTrigger>
                                <TooltipContent>
                                  <Trans
                                    message={t`Verified that this link is owned by ${"OWNER"} ${"RELATIVE_TIME"}`}
                                    values={{
                                      OWNER: () => (
                                        <strong>{actor().name}</strong>
                                      ),
                                      RELATIVE_TIME: () => (
                                        <Timestamp value={verified()} />
                                      ),
                                    }}
                                  />
                                </TooltipContent>
                              </Tooltip>
                            )}
                          </Show>
                        </li>
                      )}
                    </For>
                  </ul>
                </div>
              </Show>
            )}
          </Show>
          <div class="p-4 pt-0 border-b">
