public data class ActorByHandle(
  public val id: String,
  public val handle: String,
  public val isViewer: Boolean,
  public val viewerFollows: Boolean,
  public val followsViewer: Boolean,
  public val viewerBlocks: Boolean,
  public val name: Any?,
  public val bio: Any?,
  public val avatarUrl: Any,
  public val fields: List<Field>,
  public val account: Account?,
  public val posts: Posts,
)

public data class Field(
  public val name: String,
  public val `value`: Any,
)

public data class Account(
  public val links: List<Link>,
)

public data class Link(
  public val name: String,
  public val handle: String?,
  public val icon: AccountLinkIcon,
  public val url: Any,
  public val verified: Any?,
)

public data class Posts(
  public val edges: List<Edge>,
  public val pageInfo: PageInfo,
)

public data class Edge(
  public val cursor: String,
  public val node: Node,
)

public data class Node(
  public val __typename: String,
  public val sharedPost: SharedPost?,
  /**
   * Synthetic field for 'PostFields'
   */
  public val postFields: PostFields,
)

suspend fun getProfile(handle: String, postsAfter: String? = null): Result<ProfileResult> {
    return try {
        val response = apolloClient.query(
            ActorByHandleQuery(handle, Optional.presentIfNotNull(postsAfter))
        ).execute()

        if (response.hasErrors()) {
            Result.failure(Exception(response.errors?.firstOrNull()?.message ?: "Unknown error"))
        } else {
            val actor = response.data?.actorByHandle
                ?: return Result.failure(Exception("Actor not found"))

            Result.success(
                ProfileResult(
                    actor = Actor(
                        id = actor.id,
                        name = actor.name?.toString(),
                        handle = actor.handle,
                        avatarUrl = actor.avatarUrl.toString()
                    ),
                    bio = actor.bio?.toString(),
                    posts = actor.posts.edges.mapNotNull { edge ->
                        edge.node.postFields.toPost(edge.node.sharedPost?.sharedPostFields?.toPost())
                    },
                    hasNextPage = actor.posts.pageInfo.hasNextPage,
                    endCursor = actor.posts.pageInfo.endCursor,
                    isViewer = actor.isViewer,
                    viewerFollows = actor.viewerFollows,
                    followsViewer = actor.followsViewer,
                    viewerBlocks = actor.viewerBlocks
                )
            )
        }
    } catch (e: Exception) {
        Result.failure(e)
    }
}

