@Composable
private fun ProfileAttachments(accountLinks: List<AccountLink>) {
    val colors = LocalAppColors.current
    val typography = LocalAppTypography.current
    val uriHandler = LocalUriHandler.current

    Column(
        modifier = Modifier.fillMaxWidth(),
        verticalArrangement = Arrangement.spacedBy(4.dp)
    ) {
        accountLinks.forEach { link ->
            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier
                    .fillMaxWidth()
                    .clickable { uriHandler.openUri(link.url) }
                    .padding(horizontal = 24.dp, vertical = 4.dp)
            ) {
                Text(
                    text = link.name,
                    style = typography.caption,
                    color = colors.textSecondary
                )
                Spacer(modifier = Modifier.width(6.dp))
                Text(
                    text = link.handle ?: compactUrl(link.url),
                    style = typography.caption,
                    color = colors.accent,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis,
                    modifier = Modifier.weight(1f, fill = false)
                )
                if (link.verified != null) {
                    Spacer(modifier = Modifier.width(4.dp))
                    Icon(
                        imageVector = Icons.Filled.CheckCircle,
                        contentDescription = stringResource(R.string.profile_verified),
                        modifier = Modifier.size(14.dp),
                        tint = Color(0xFF22C55E)
                    )
                }
            }
        }
    }
}

@Composable
private fun ProfileFields(fields: List<ActorField>) {
    val colors = LocalAppColors.current
    val typography = LocalAppTypography.current

    Column(
        modifier = Modifier.fillMaxWidth(),
        verticalArrangement = Arrangement.spacedBy(4.dp)
    ) {
        fields.forEach { field ->
            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 24.dp, vertical = 4.dp)
            ) {
                Text(
                    text = field.name,
                    style = typography.caption,
                    color = colors.textSecondary
                )
                Spacer(modifier = Modifier.width(6.dp))
                HtmlContent(
                    html = field.value,
                    modifier = Modifier.weight(1f, fill = false)
                )
            }
        }
    }
}

private fun compactUrl(url: String): String {
    return url
        .removePrefix("https://")
        .removePrefix("http://")
        .removePrefix("www.")
        .trimEnd('/')
}

